import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(coord1, coord2):
        return np.linalg.norm(coord1 - coord2)

    def time_to_reach(start_pos, end_pos, speed):
        distance = euclidean_distance(start_pos, end_pos)
        return distance / speed

    remaining_times = []
    num_customers = len(unvisited_customers)

    for index, customer in enumerate(unvisited_customers):
        travel_time = time_to_reach(cur_truck_pos, customer, truck_speed)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[index]

        # Calculate how fitting the arrival time is within the time window
        if arrival_time < start_window:
            wait_time = start_window - arrival_time
        elif arrival_time > end_window:
            wait_time = arrival_time - end_window
        else:
            wait_time = 0

        urgency = end_window - current_time  # Less time till end of window, more urgent
        score = wait_time + (0.1 * urgency)  # Minimize wait time, consider urgency with less weigh
        remaining_times.append((score, index))

    # Sort primarily by score then by arrival time within window
    remaining_times.sort()

    # Find the best node index if it exists, otherwise return None to wait
    if remaining_times:
        best_node = remaining_times[0][1]
    else:
        best_node = None

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def weighted_distance_score(truck_pos, customer_pos, truck_density):
        direct_distance = np.linalg.norm(customer_pos - truck_pos)
        density_penalty = truck_density * np.log(1+direct_distance)
        return direct_distance + density_penalty

    def compute_time_window_score(time_to_reach, time_window_start, time_window_end):
        if current_time + time_to_reach < time_window_start:
            return 2 * (time_window_start - (current_time + time_to_reach))
        elif current_time + time_to_reach > time_window_end:
            return 3 * ((current_time + time_to_reach) - time_window_end)
        else:
            return 0

    mean_truck_position = np.mean(all_truck_pos, axis=0)
    all_distances_to_mean = np.linalg.norm(all_truck_pos - mean_truck_position, axis=1)
    standard_deviation_of_position = np.std(all_distances_to_mean)
    truck_density = len(all_truck_pos) / (np.pi * (standard_deviation_of_position ** 2 + 1))

    scores = []

    for idx, customer in enumerate(unvisited_customers):
        time_to_customer = np.linalg.norm(customer - cur_truck_pos) / truck_speed
        time_window_start, time_window_end = time_windows[idx]

        dist_score = weighted_distance_score(cur_truck_pos, customer, truck_density)
        tw_score = compute_time_window_score(time_to_customer, time_window_start, time_window_end)

        final_score = dist_score + tw_score
        scores.append(final_score)

    if all(score > 1000 for score in scores):  # Arbitrary large penalty cutoff for unserviceability
        best_node = None
    else:
        best_node = np.argmin(scores)

    return best_node
